def asset = ctx.asset; if (asset == null) return;
for (String f : new String[]{'name','fqdn','type','status'}) {
  if (asset.containsKey(f) && asset[f] instanceof Map && ((Map)asset[f]).size() == 1) {
    asset[f] = ((Map)asset[f]).values().iterator().next();
  }
}
def hw = asset.get('hardware');
if (hw instanceof Map) {
  for (String f : new String[]{'manufacturer','model','serial_number','bios_uuid','chassis_type'}) {
    if (hw.containsKey(f) && hw[f] instanceof Map && ((Map)hw[f]).size() == 1) {
      hw[f] = ((Map)hw[f]).values().iterator().next();
    }
  }
  def cpu = hw.get('cpu');
  if (cpu instanceof Map && cpu.containsKey('brand') && cpu['brand'] instanceof Map && ((Map)cpu['brand']).size() == 1) {
    cpu['brand'] = ((Map)cpu['brand']).values().iterator().next();
  }
}
def os = asset.get('os');
if (os instanceof Map) {
  for (String f : new String[]{'name','version','build','platform','architecture'}) {
    if (os.containsKey(f) && os[f] instanceof Map && ((Map)os[f]).size() == 1) {
      os[f] = ((Map)os[f]).values().iterator().next();
    }
  }
}
def org = asset.get('organization');
if (org instanceof Map) {
  for (String f : new String[]{'owner','department','location'}) {
    if (org.containsKey(f) && org[f] instanceof Map && ((Map)org[f]).size() == 1) {
      org[f] = ((Map)org[f]).values().iterator().next();
    }
  }
}

def asset = ctx.asset; if (asset == null) return;

// Remove string 'null' from top-level asset fields
for (String f : new String[]{'name','fqdn','type','status'}) {
  if ('null'.equals(asset.get(f))) asset.remove(f);
}

// Convert managed string boolean
def mv = asset.get('managed');
if ('true'.equals(mv)) asset['managed'] = true;
else if ('false'.equals(mv)) asset['managed'] = false;

// Clean hardware nulls and string booleans
def hw = asset.get('hardware');
if (hw instanceof Map) {
  for (String f : new String[]{'manufacturer','model','serial_number','bios_uuid','chassis_type'}) {
    if ('null'.equals(hw.get(f))) ((Map)hw).remove(f);
  }
  def cpu = ((Map)hw).get('cpu');
  if (cpu instanceof Map && 'null'.equals(((Map)cpu).get('brand'))) ((Map)cpu).remove('brand');
}

// Clean OS nulls
def os = asset.get('os');
if (os instanceof Map) {
  for (String f : new String[]{'name','version','build','platform','architecture'}) {
    if ('null'.equals(((Map)os).get(f))) ((Map)os).remove(f);
  }
}

// Clean org nulls
def org = asset.get('organization');
if (org instanceof Map) {
  for (String f : new String[]{'owner','department','location'}) {
    if ('null'.equals(((Map)org).get(f))) ((Map)org).remove(f);
  }
}

// Convert compliance string booleans and remove nulls
def comp = asset.get('compliance');
if (comp instanceof Map) {
  for (String f : new String[]{'encrypted','mdm_enrolled','mdm_compliant','patch_compliant'}) {
    def v = ((Map)comp).get(f);
    if ('true'.equals(v)) ((Map)comp)[f] = true;
    else if ('false'.equals(v)) ((Map)comp)[f] = false;
    else if ('null'.equals(v)) ((Map)comp).remove(f);
  }
}

def asset = ctx.asset; if (asset == null) return;
String hn = null;
if (asset.get('name') != null && asset.get('name').toString().length() > 0) hn = asset.get('name').toString();
else if (asset.get('fqdn') != null && asset.get('fqdn').toString().length() > 0) hn = asset.get('fqdn').toString();
if (hn != null) {
  if (!ctx.containsKey('host') || ctx.host == null) ctx['host'] = new HashMap();
  ctx.host['name'] = hn.toLowerCase();
}

def asset = ctx.asset; if (asset == null) return;
if (asset.get('component') != null && asset.get('component').toString().length() > 0) return;
String component = null;
def org = asset.get('organization');
if (org instanceof Map) {
  if (org.get('department') != null && org.get('department').toString().length() > 0) component = org.get('department').toString();
  else if (org.get('owner') != null && org.get('owner').toString().length() > 0) component = org.get('owner').toString();
}
asset['component'] = (component != null) ? component : 'unattributed';

if (!ctx.containsKey('m_26_14') || ctx.m_26_14 == null) ctx['m_26_14'] = new HashMap();

// Element 1: managed AND seen. Handle boolean, numeric, and string forms.
def managedVal = ctx?.asset?.managed;
boolean managed = (managedVal == true) ||
                  (managedVal instanceof Number && ((Number)managedVal).intValue() == 1) ||
                  'true'.equals(managedVal);
boolean hasSeen = ctx?.asset?.last_seen != null;
ctx.m_26_14['element1_covered'] = managed && hasSeen;

// Element 2: sourced from a SWAM-capable tool
boolean hasSwam = false;
def hwam = ctx?.m_26_14?.get('hwam_source');
if (hwam != null) {
  def sources = (hwam instanceof List) ? hwam : [hwam.toString()];
  def swamSources = new HashSet(['osquery','qualys','crowdstrike','tanium','jamf']);
  for (def s : sources) {
    if (swamSources.contains(s.toString())) { hasSwam = true; break; }
  }
}
ctx.m_26_14['element2_covered'] = hasSwam;

if (!(ctx.get('m_26_14') instanceof Map)) ctx['m_26_14'] = new HashMap();
def cur = ((Map)ctx.get('m_26_14')).get('baseline_hash');
def base = null;
def b = ctx.get('_baseline');
if (b instanceof Map) {
  def bm = ((Map)b).get('m_26_14');
  if (bm instanceof Map) base = ((Map)bm).get('baseline_hash');
}
boolean drift = (base != null && cur != null && !base.equals(cur));
((Map)ctx.get('m_26_14'))['drift_detected'] = drift;
def asset = ctx.asset;
if (asset instanceof Map) {
  if (!(asset.get('compliance') instanceof Map)) asset['compliance'] = new HashMap();
  ((Map)asset.get('compliance'))['drift_detected'] = drift;
}
